library(dslabs) data(“polls_us_election_2016”) data &lt;- polls_us_election_2016 my_first &lt;- “Sena” my_birth_year &lt;- 2002 k &lt;- (nchar(my_first) + my_birth_year) %% 15 + 8 k



if (k %% 2 == 0) { head(data, k) } else { tail(data, k) }



sum(is.na(data))



na_counts &lt;- sort(colSums(is.na(data)), decreasing = TRUE) head(na_counts, 8)



new_data &lt;- data
for (col in names(new_data)) {
if (is.numeric(new_data[[col]])) { new_data[[col]][is.na(new_data[[col]])] &lt;- my_birth_year + k
} else if (inherits(new_data[[col]], “Date”)) { new_data[[col]][is.na(new_data[[col]])] &lt;- as.Date(“2002-01-19”)
} else if (is.factor(new_data[[col]])) { new_data[[col]] &lt;- as.character(new_data[[col]]) new_data[[col]][is.na(new_data[[col]])] &lt;- paste0(my_first, “_“, k)
} else if (is.character(new_data[[col]])) { new_data[[col]][is.na(new_data[[col]])] &lt;- paste0(my_first, “_“, k) }
}



if (k %% 2 == 0) { head(new_data, k) } else { tail(new_data, k) }



sum(is.na(new_data))



anyNA(new_data)
